mapper.select:
select issue_status_id, status_name, closed_yn from issue_status where user_id = #{userId}
and closed_yn = #{closedYn}
order by case closed_yn when 'N' then 1 when 'Y' then 2 else 3 end, status_name, issue_status_id

select count(*)
from issue_type
where issue_type_id = #{issueTypeId}
and user_id =
#{userId}

select count(*)
from role
where
role_id = #{roleId}
and created_by = #{userId}

select count(distinct issue_status_id) from issue_status where user_id = #{userId}
and issue_status_id in
#{statusId}
and 1 = 0

mapper.delete:
delete from workflow_transition wt
where wt.issue_type_id =
#{issueTypeId}
and wt.role_id = #{roleId}
and wt.apply_target_code =
#{applyTargetCode}
and exists (
select 1
from issue_type it
where
it.issue_type_id = wt.issue_type_id
and it.user_id = #{userId}
)
and
exists (
select 1
from role r
where r.role_id = wt.role_id
and
r.created_by = #{userId}
)


	and exists (
	select 1
	from issue_status ts
	where
	ts.issue_status_id = wt.to_status_id
	and ts.user_id = #{userId}
	and ts.closed_yn = #{closedYn}
	)
